import { Link } from 'lucide-react'
import React from 'react'

const Header = () => {
  return (
    <header>
    <div className='main-container inner'>
    <Link href='/'>
    <Image src="../public/logo.svg" alt="logo" width={100} height={100} className="object-contain" />
    </Link>
    </div>
    </header>
  )
}

export default Header
